"""Инициализация QApplication и запуск главного окна."""from __future__ import annotationsimport sysfrom .core.pipeline import ExperimentPipelinefrom .core.registry import create_default_registryfrom .infrastructure.config import CONFIGfrom .infrastructure.logger import setup_loggerfrom .infrastructure.paths import ensure_runtime_dirsdef run_gui() -> int:    ensure_runtime_dirs()    log = setup_logger()    log.info("%s v%s starting GUI.", CONFIG.app_name, CONFIG.version)    from PySide6.QtWidgets import QApplication    from .gui.main_window import MainWindow    app = QApplication.instance() or QApplication(sys.argv)    app.setApplicationName(CONFIG.app_name)    registry = create_default_registry()    pipeline = ExperimentPipeline(registry)    window = MainWindow(registry=registry, pipeline=pipeline)    window.resize(1280, 760)    window.show()    return int(app.exec())